# ── Helpers ───────────────────────────────────────────────────────────────────
def ltext(value, size=12, color=None, spacing=2, weight=None, expand=False):
    return ft.Text(value, size=size, color=color or TEXT_MUTED,
                   weight=weight, expand=expand,
                   style=ft.TextStyle(letter_spacing=spacing))

def page_header(title, tag, subtitle=""):
    return ft.Column([
        ft.Row([
            ft.Text(title, size=22, weight=ft.FontWeight.BOLD, color=TEXT_PRI, expand=True),
            ft.Container(ft.Text(tag, size=10, color=ACCENT_DARK),
                         bgcolor=ACCENT_DIM,
                         padding=ft.Padding.symmetric(horizontal=10, vertical=4),
                         border_radius=20),
        ], spacing=10),
        ft.Text(subtitle, size=11, color=TEXT_MUTED) if subtitle else ft.Container(height=0),
        ft.Container(height=2, bgcolor=ACCENT, border_radius=2,
                     margin=ft.Margin.only(top=6, bottom=2), width=50),
    ], spacing=4)

def card(content, padding=16):
    return ft.Container(content=content, bgcolor=WHITE,
                        border=ft.Border.all(1, ACCENT_LITE),
                        border_radius=14, padding=padding,
                        shadow=ft.BoxShadow(blur_radius=8, color="#1A7C3AED",
                                            offset=ft.Offset(0, 2)))

def section_label(text):
    return ft.Row([
        ft.Container(width=3, height=16, bgcolor=ACCENT, border_radius=2),
        ltext(text.upper(), size=10, color=ACCENT, spacing=2, weight=ft.FontWeight.BOLD),
    ], spacing=8)

def info_banner(text, icon=ft.Icons.INFO_OUTLINE):
    return ft.Container(
        content=ft.Row([ft.Icon(icon, color=ACCENT, size=18),
                        ft.Text(text, size=12, color=ACCENT_DARK, expand=True)],
                       spacing=10),
        bgcolor=ACCENT_DIM, border=ft.Border.all(1, ACCENT_MID),
        border_radius=10, padding=ft.Padding.symmetric(horizontal=14, vertical=12))

def status_pill(text):
    s = {"Done": (ACCENT_DIM, ACCENT), "In Progress": ("#FEF3C7","#92400E"),
         "Planned": (SURFACE, TEXT_MUTED)}
    bg, fg = s.get(text, (SURFACE, TEXT_MUTED))
    return ft.Container(ft.Text(text, size=10, color=fg, weight=ft.FontWeight.BOLD),
                        bgcolor=bg, padding=ft.Padding.symmetric(horizontal=8, vertical=4),
                        border_radius=12)

def small_tag(text):
    return ft.Container(ft.Text(text, size=10, color=ACCENT), bgcolor=ACCENT_DIM,
                        padding=ft.Padding.symmetric(horizontal=7, vertical=3),
                        border_radius=10)

def math_block(label, lines):
    return ft.Container(
        content=ft.Column([
            ltext(label, size=9, color=ACCENT, spacing=1, weight=ft.FontWeight.BOLD),
            *[ft.Text(l, size=12, color=TEXT_PRI, font_family="Courier New") for l in lines],
        ], spacing=4),
        bgcolor=SURFACE, border=ft.Border.only(left=ft.BorderSide(3, ACCENT)),
        border_radius=ft.BorderRadius.only(top_right=8, bottom_right=8),
        padding=ft.Padding.symmetric(horizontal=14, vertical=12))

