def blog_view():
    import os, shutil
    import flet_video as fv

    src_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "video.mp4")
    assets_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), "assets")
    dst_path = os.path.join(assets_dir, "video.mp4")

    video_available = False
    if os.path.exists(src_path):
        os.makedirs(assets_dir, exist_ok=True)
        if not os.path.exists(dst_path):
            shutil.copy2(src_path, dst_path)
        video_available = True

    if video_available:
        video_uri = src_path.replace("\\", "/")
        if not video_uri.startswith("/"):
            video_uri = "/" + video_uri
        video_uri = "file://" + video_uri

        video_widget = fv.Video(
            playlist=[fv.VideoMedia(video_uri)],
            autoplay=True,
            width=680,
            height=383,
        )
        video_content = ft.Column([
            ft.Row([
                ft.Container(
                    ft.Icon(ft.Icons.PLAY_CIRCLE, color=ACCENT, size=18),
                    bgcolor=SURFACE, border_radius=20,
                    padding=ft.Padding.symmetric(horizontal=8, vertical=8),
                ),
                ft.Column([
                    ft.Text("Safe Sphere — Semester Contribution Video", size=13,
                            weight=ft.FontWeight.BOLD, color=TEXT_PRI),
                    ft.Text("Plays directly below", size=11, color=TEXT_MUTED),
                ], spacing=2, expand=True),
                ft.Container(
                    ft.Text("1:30 MAX", size=9, color="#EA580C",
                            weight=ft.FontWeight.BOLD),
                    bgcolor="#FFF7ED", border_radius=6,
                    padding=ft.Padding.symmetric(horizontal=8, vertical=4),
                    border=ft.Border.all(1, "#EA580C"),
                ),
            ], spacing=12, vertical_alignment=ft.CrossAxisAlignment.CENTER),
            ft.Container(height=10),
            video_widget,
        ], spacing=0)
    else:
        video_content = ft.Column([
            ft.Icon(ft.Icons.VIDEO_CALL, color=ACCENT, size=42),
            ft.Text("Pavement watch — Semester Contribution Video", size=14,
                    weight=ft.FontWeight.BOLD, color=TEXT_PRI,
                    text_align=ft.TextAlign.CENTER),
            ft.Text("Put video.mp4 in the same folder as main2.py",
                    size=11, color=TEXT_MUTED, text_align=ft.TextAlign.CENTER),
            ft.Container(
                ft.Text("1 minute 30 seconds maximum", size=10, color="#EA580C",
                        weight=ft.FontWeight.BOLD),
                bgcolor="#FFF7ED", border_radius=6,
                padding=ft.Padding.symmetric(horizontal=10, vertical=4),
                border=ft.Border.all(1, "#EA580C"),
            ),
        ], spacing=8, horizontal_alignment=ft.CrossAxisAlignment.CENTER)

    video_section = ft.Container(
        content=video_content,
        bgcolor=WHITE, border_radius=16, padding=16,
        border=ft.Border.all(1, ACCENT_LITE),
        shadow=ft.BoxShadow(blur_radius=20, color="#1A7C3AED", offset=ft.Offset(0, 4)),
    )

    post_cards = []
    for post in BLOG_POST:
        bullets = ft.Column([
            ft.Row([
                ft.Container(width=6, height=6, bgcolor=post["color"],
                             border_radius=3, margin=ft.Margin.only(top=4)),
                ft.Text(b, size=12, color=TEXT_SEC, expand=True),
            ], spacing=10, vertical_alignment=ft.CrossAxisAlignment.START)
            for b in post["bullets"]
        ], spacing=6)

        post_cards.append(ft.Container(
            content=ft.Column([
                ft.Container(
                    content=ft.Row([
                        ft.Container(width=4, height=36, bgcolor=post["color"],
                                     border_radius=2),
                        ft.Column([
                            ltext(post["label"], size=9, color=post["color"],
                                  spacing=2, weight=ft.FontWeight.BOLD),
                            ft.Text(post["title"], size=14,
                                    weight=ft.FontWeight.BOLD, color=TEXT_PRI),
                        ], spacing=2, expand=True),
                    ], spacing=10, vertical_alignment=ft.CrossAxisAlignment.CENTER),
                    bgcolor=post["bg"],
                    border_radius=ft.BorderRadius.only(top_left=10, top_right=10,
                                                       bottom_left=0, bottom_right=0),
                    padding=ft.Padding.symmetric(horizontal=16, vertical=14),
                ),
                ft.Container(
                    content=ft.Column([
                        ft.Text(post["body"], size=13, color=TEXT_SEC, selectable=True),
                        ft.Container(height=8),
                        bullets,
                    ], spacing=0),
                    padding=ft.Padding.symmetric(horizontal=16, vertical=14),
                ),
            ], spacing=0),
            bgcolor=WHITE, border=ft.Border.all(1, ACCENT_LITE),
            border_radius=10, clip_behavior=ft.ClipBehavior.ANTI_ALIAS,
            shadow=ft.BoxShadow(blur_radius=6, color="#0F000000", offset=ft.Offset(0, 2)),
        ))

    return ft.Column([
        page_header("Technical Blog", "CONFIDENCE IN CONCEPTS",
                    "Tuna Matengu — Pavement-Watch"),
        ft.Container(height=8),
        section_label("Semester contribution video"),
        ft.Container(height=8),
        video_section,
        ft.Container(height=16),
        section_label("Concepts demonstrated in Pavement-Watch"),
        ft.Container(height=8),
        *post_cards,
        ft.Container(height=20),
    ], spacing=12, scroll=ft.ScrollMode.AUTO, expand=True)


# PAGE 4 MATLAB HUB
