def matlab_view():
    image_display = ft.Container(
        content=ft.Column([
            ft.Icon(ft.Icons.TOUCH_APP, color=ACCENT_MID, size=36),
            ft.Text("Click any certificate below to view it",
                    size=13, color=TEXT_MUTED, text_align=ft.TextAlign.CENTER),
        ], spacing=8, horizontal_alignment=ft.CrossAxisAlignment.CENTER),
        bgcolor=SURFACE, border_radius=14, border=ft.Border.all(1, ACCENT_LITE),
        padding=40, alignment=ft.Alignment(0, 0), height=280,
    )

    def make_tile(course):
        def on_click(_):
            img_src = CERT_IMAGES.get(course["key"], "")
            image_display.content = ft.Column([
                ft.Text(course["name"], size=14, weight=ft.FontWeight.BOLD,
                        color=TEXT_PRI, text_align=ft.TextAlign.CENTER),
                ft.Text("Completed: " + course["date"], size=11,
                        color=ACCENT, text_align=ft.TextAlign.CENTER),
                ft.Image(src=img_src, width=500, fit="contain")
                if img_src and len(img_src) > 10 else
                ft.Text("Image not found. Make sure the .jpg file is in the same folder as main.py",
                        size=11, color="#EF4444", text_align=ft.TextAlign.CENTER),
            ], spacing=8, horizontal_alignment=ft.CrossAxisAlignment.CENTER)
            image_display.height = None
            image_display.update()

        return ft.Container(
            content=ft.Row([
                ft.Container(ft.Icon(ft.Icons.VERIFIED, color=WHITE, size=16),
                             width=30, height=30, bgcolor=ACCENT, border_radius=15,
                             alignment=ft.Alignment(0, 0)),
                ft.Column([
                    ft.Text(course["name"], size=12, weight=ft.FontWeight.BOLD, color=TEXT_PRI),
                    ft.Text(course["date"], size=10, color=ACCENT),
                ], spacing=2, expand=True),
                ft.Icon(ft.Icons.CHEVRON_RIGHT, color=ACCENT_MID, size=18),
            ], spacing=10, vertical_alignment=ft.CrossAxisAlignment.CENTER),
            bgcolor=WHITE, border=ft.Border.all(1, ACCENT_LITE),
            border_radius=10, padding=ft.Padding.symmetric(horizontal=14, vertical=10),
            on_click=on_click, ink=True, expand=True,
        )

    tiles = [make_tile(c) for c in COURSES]
    grid_rows = []
    for i in range(0, len(tiles), 2):
        pair = tiles[i:i+2]
        if len(pair) == 2:
            grid_rows.append(ft.Row(pair, spacing=10, expand=True))
        else:
            grid_rows.append(ft.Row([pair[0], ft.Container(expand=True)], spacing=10, expand=True))

    return ft.Column([
        page_header("MATLAB Achievement Hub", "8 CERTIFICATES",
                    "Tuna Matengu MathWorks Learning Center"),
        ft.Container(height=8),
        ft.Container(
            content=ft.Row([
                ft.Icon(ft.Icons.EMOJI_EVENTS, color=ACCENT, size=22),
                ft.Text("8 of 8 courses completed 100%", size=14,
                        weight=ft.FontWeight.BOLD, color=ACCENT_DARK, expand=True),
                ft.Container(ft.Text("ALL DONE", size=10, color=WHITE,
                                     weight=ft.FontWeight.BOLD),
                             bgcolor=ACCENT,
                             padding=ft.Padding.symmetric(horizontal=10, vertical=4),
                             border_radius=12),
            ], spacing=10),
            bgcolor=ACCENT_DIM, border=ft.Border.all(1, ACCENT_MID),
            border_radius=10, padding=ft.Padding.symmetric(horizontal=16, vertical=12),
        ),
        ft.Container(height=6),
        ft.ProgressBar(value=1.0, bgcolor="#E5E7EB", color=ACCENT, height=8,
                       border_radius=ft.BorderRadius.only(
                           top_left=4, top_right=4, bottom_left=4, bottom_right=4)),
        ft.Container(height=14),
        section_label("Click any certificate to view"),
        ft.Container(height=8),
        image_display,
        ft.Container(height=14),
        section_label("All 8 completed courses"),
        ft.Container(height=8),
        ft.Column(grid_rows, spacing=10),
        ft.Container(height=20),
    ], spacing=8, scroll=ft.ScrollMode.AUTO, expand=True)


