def build_sidebar(page, active):
    def make_btn(label, icon, key):
        is_active = key == active
        def on_click(_):
            page.data["active"] = key
            rebuild(page)
        return ft.Container(
            content=ft.Row([
                ft.Container(ft.Icon(icon, color=WHITE if is_active else ACCENT_MID, size=18),
                             width=34, height=34,
                             bgcolor="#FFFFFF20" if is_active else "transparent",
                             border_radius=8, alignment=ft.Alignment(0, 0)),
                ft.Text(label, color=WHITE if is_active else ACCENT_LITE, size=13,
                        weight=ft.FontWeight.BOLD if is_active else ft.FontWeight.NORMAL),
            ], spacing=10),
            padding=ft.Padding.symmetric(horizontal=14, vertical=10),
            border=ft.Border.only(left=ft.BorderSide(3, WHITE if is_active else "transparent")),
            bgcolor="#FFFFFF18" if is_active else "transparent",
            border_radius=ft.BorderRadius.only(top_right=8, bottom_right=8),
            on_click=on_click, ink=True,
            margin=ft.Margin.only(right=10),
        )

    return ft.Container(
        width=220, bgcolor=NAV_BG,
        content=ft.Column([
            ft.Container(
                content=ft.Column([
                    ft.Container(
                        content=(
                            ft.Container(
                                content=ft.Image(src=PROFILE_PHOTO_PATH,
                                                 width=52, height=52, fit="cover"),
                                width=52, height=52, border_radius=26,
                                clip_behavior=ft.ClipBehavior.ANTI_ALIAS,
                            )
                            if PROFILE_PHOTO_PATH and len(PROFILE_PHOTO_PATH) > 10 else
                            ft.Text("TM", color=WHITE, size=22, weight=ft.FontWeight.BOLD,
                                    text_align=ft.TextAlign.CENTER)
                        ),
                        width=52, height=52, bgcolor="#FFFFFF25", border_radius=26,
                        alignment=ft.Alignment(0, 0),
                        border=ft.Border.all(2, ACCENT_MID),
                        clip_behavior=ft.ClipBehavior.ANTI_ALIAS,
                    ),
                    ft.Text("Tuna Matengu", color=WHITE, size=14, weight=ft.FontWeight.BOLD),
                    ft.Text("Documentation Lead", color=ACCENT_MID, size=10),
                    ft.Text("Group 9 | I3691CP", color="#FFFFFF55", size=10),
                ], spacing=4, horizontal_alignment=ft.CrossAxisAlignment.CENTER),
                padding=ft.Padding.only(left=16, right=16, top=28, bottom=20),
                border=ft.Border.only(bottom=ft.BorderSide(1, "#FFFFFF20")),
            ),
            ft.Container(ltext("NAVIGATION", size=9, color="#FFFFFF55", spacing=2),
                         padding=ft.Padding.only(left=18, top=14, bottom=6)),
            *[make_btn(l, i, k) for l, i, k in NAV_ITEMS],
            ft.Container(expand=True),
            ft.Container(
                content=ft.Column([
                    ft.Row([ft.Icon(ft.Icons.LOCATION_CITY, color=ACCENT_MID, size=14),
                            ft.Text("Pavement-Watch", color=WHITE, size=12,
                                    weight=ft.FontWeight.BOLD)], spacing=6),
                    ft.Text("Civil Engineering App", color=ACCENT_MID, size=10),
                    ft.Text("UNAM JEDS Campus", color="#FFFFFF55", size=10),
                ], spacing=3),
                margin=ft.Margin.only(left=12, right=12, bottom=20),
                padding=12, bgcolor=NAV_DARK, border_radius=10,
                border=ft.Border.all(1, "#FFFFFF20"),
            ),
        ], spacing=0, expand=True),
    )

def rebuild(page):
    active = page.data.get("active", "timeline")
    content = VIEW_MAP[active]()
    page.controls.clear()
    page.controls.append(
        ft.Row([
            build_sidebar(page, active),
            ft.Container(content=content, expand=True, bgcolor=PAGE_BG,
                         padding=ft.Padding.only(left=30, right=30, top=26, bottom=0)),
        ], spacing=0, expand=True)
    )
    page.update()

def main(page: ft.Page):
    page.title         = "Tuna Matengu Pavement-Watch Portfolio"
    page.theme_mode    = ft.ThemeMode.LIGHT
    page.bgcolor       = PAGE_BG
    page.padding       = 0
    page.window.width  = 1150
    page.window.height = 780
    page.data          = {"active": "timeline"}
    rebuild(page)

ft.run(main, assets_dir="assets")